.darma-loader-darma-custom-590 {color: var(--loader-color, #0f766e);
   width: 60px;
   aspect-ratio: 1;
   background: linear-gradient(45deg,var(--loader-color, #0f766e) 50%,#0000 0), linear-gradient(45deg,#0000 50%,var(--loader-color, #0f766e) 0), linear-gradient(-45deg,var(--loader-color, #0f766e) 50%,#0000 0), linear-gradient(-45deg,#0000 50%,var(--loader-color, #0f766e) 0), linear-gradient(var(--loader-color, #0f766e) 0 0);
   background-size: 50% 50%;
   background-repeat: no-repeat;
   animation: darma-loader-darma-custom-590-l17 1s infinite alternate;
}
@keyframes darma-loader-darma-custom-590-l17 {
  0%, 20% {background-position:50% 50%,50% 50%,50% 50% ,50% 50%,50% 50%;
   background-size:50% 50%,50% 50%,50% 50%,50% 50%,50% 50%}
80%, 100% {background-position:0 100%,100% 0,100% 100%,0 0 ,50% 50%;
   background-size:50% 50%,50% 50%,50% 50%,50% 50%,100% 100%}
}

